+        () => notebook.Count == 0
+            ? "No notes saved yet."
+            : string.Join("\n---\n", notebook.Notes),
+        "ReadNotes",
+        "Read all saved research notes"),
+];
+
+// --- Chat client pipeline ----------------------------------------------------
+IChatClient chatClient = new ChatClientBuilder(
+        new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
+    .UseFunctionInvocation(options => options.MaximumIterationsPerRequest = 10)
+    .Build();
+
+// --- Agent -------------------------------------------------------------------
+var agent = new ChatClientAgent(chatClient, new ChatClientAgentOptions
+{
+    Name = "ResearchAgent",
+    Description = "An AI agent that researches topics by searching the web and taking notes.",
+    ChatOptions = new ChatOptions
+    {
+        Temperature = 0f,
+        MaxOutputTokens = 2048,
+        Tools = [.. tools],
+    },
+});
+
+string instructions = """
+    You are a research assistant. When given a topic:
+    1. Use SearchWeb to find relevant information (make 2-3 searches with different queries).
+    2. Use SaveNote to record key findings from each search.
+    3. Use ReadNotes to review everything you collected.
+    4. Provide a well-structured summary with key points and sources.
+    Be thorough but concise. Always cite your sources.
+    """;
+
+// --- Run ---------------------------------------------------------------------
+Console.Write("Enter a research topic: ");
+var topic = Console.ReadLine()?.Trim();
+if (string.IsNullOrEmpty(topic))
+{
+    Console.Error.WriteLine("No topic provided.");
+    return;
+}
+
+Console.WriteLine($"\nResearching: {topic}\n");
+
+var session = await agent.CreateSessionAsync();
+var response = await agent.RunAsync(
+    [
+        new(ChatRole.System, instructions),
+        new(ChatRole.User, $"Research the following topic and provide a summary: {topic}"),
+    ],
+    session);
+
+Console.WriteLine(response.Message.Text);
+Console.WriteLine($"\n--- Research complete ({notebook.Count} notes taken) ---");

