using System.ComponentModel;
using System.Net;
using System.Text.Json;
using System.Text.RegularExpressions;

namespace ResearchAgent;

/// <summary>
/// Provides a web search tool that uses DuckDuckGo's instant answer API
/// and scrapes snippets from result pages.
/// </summary>
public static partial class WebSearchTool
{
    private static readonly HttpClient HttpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    [Description("Search the web for a query and return relevant snippets with source URLs.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            // Use DuckDuckGo instant answer API
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var json = await HttpClient.GetStringAsync(url, cancellationToken);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract (main answer)
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[Source: {abstractUrl}]\n{abstractText}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add($"[Source: {firstUrl}]\n{text}");
                    }
                }
            }

            if (results.Count == 0)
            {
                // Fallback: use DuckDuckGo HTML search and extract snippets
                return await ScrapeSearchResultsAsync(query, cancellationToken);
            }

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static async Task<string> ScrapeSearchResultsAsync(
        string query, CancellationToken cancellationToken)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            var html = await HttpClient.GetStringAsync(url, cancellationToken);

            var results = new List<string>();
            var snippetMatches = SnippetRegex().Matches(html);

            foreach (Match match in snippetMatches.Take(5))
            {
                var snippet = WebUtility.HtmlDecode(
                    StripHtmlRegex().Replace(match.Groups[1].Value, "").Trim());
                if (!string.IsNullOrWhiteSpace(snippet))
                {
                    results.Add(snippet);
                }
            }

            return results.Count > 0
                ? $"Search results for '{query}':\n\n" + string.Join("\n\n", results)
                : $"No results found for '{query}'.";
        }
        catch (Exception ex)
        {
            return $"Fallback search failed: {ex.Message}";
        }
    }

    [GeneratedRegex("""class="result__snippet"[^>]*>(.*?)</""", RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex StripHtmlRegex();
}

namespace ResearchAgent;

/// <summary>
/// A simple in-memory notebook for storing research notes.
/// </summary>
public sealed class Notebook
{
    private readonly List<string> _notes = [];

    public IReadOnlyList<string> Notes => _notes;

    public int Count => _notes.Count;

    public void Add(string note)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(note);
        _notes.Add(note);
    }
}

